import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';

const emailRegex = /^[\w-.]+@([\w-]+\.)+[\w-]{2,4}$/;
const specialCharRegex = /[!@#$%^&*(),.?":{}|<>]/;
const uppercaseRegex = /[A-Z]/;

const Register: React.FC = () => {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [touched, setTouched] = useState({ name: false, email: false, password: false });
  const navigate = useNavigate();

  const emailValid = useMemo(() => emailRegex.test(email), [email]);
  const passwordLengthValid = password.length >= 8;
  const passwordUpperValid = uppercaseRegex.test(password);
  const passwordSpecialValid = specialCharRegex.test(password);
  const nameValid = name.trim().length > 0;

  const allValid = emailValid && passwordLengthValid && passwordUpperValid && passwordSpecialValid && nameValid;

  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    setTouched({ name: true, email: true, password: true });
    if (!allValid) return;

    // TODO: call backend register API
    // For now navigate to home as if registration succeeded
    navigate('/');
  };

  return (
    <div className="max-w-md mx-auto mt-12 p-6 bg-[#0a0a0a] rounded-lg shadow-xl border border-[#C5A059]/30 glass text-white">
      <h2 className="ghost-header-md text-center mb-4">Create an account</h2>
      <form onSubmit={handleCreate} noValidate>
        <label className="block mb-3">
          <span className="label-tech-luxury opacity-60 mb-1">Name</span>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            onBlur={() => setTouched((t) => ({ ...t, name: true }))}
            className="mt-1 block w-full rounded bg-[#020202] border border-slate-700/50 text-white shadow-sm focus:ring-[#00FF41]/50 focus:border-[#00FF41]/50"
            placeholder="Your full name"
            required
          />
          {touched.name && !nameValid && (
            <div className="text-[#FF3E3E] text-sm mt-1">Please enter your name.</div>
          )}
        </label>

        <label className="block mb-3">
          <span className="label-tech-luxury opacity-60 mb-1">Email</span>
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            onBlur={() => setTouched((t) => ({ ...t, email: true }))}
            className="mt-1 block w-full rounded bg-[#020202] border border-slate-700/50 text-white shadow-sm focus:ring-[#00FF41]/50 focus:border-[#00FF41]/50"
            placeholder="you@example.com"
            required
          />
          {touched.email && !emailValid && (
            <div className="text-[#FF3E3E] text-sm mt-1">Please enter a valid email address.</div>
          )}
        </label>

        <label className="block mb-2">
          <span className="label-tech-luxury opacity-60 mb-1">Password</span>
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            onBlur={() => setTouched((t) => ({ ...t, password: true }))}
            className="mt-1 block w-full rounded bg-[#020202] border border-slate-700/50 text-white shadow-sm focus:ring-[#00FF41]/50 focus:border-[#00FF41]/50"
            placeholder="Create a password"
            required
          />
        </label>

        <ul className="text-sm mb-4 ml-4 list-disc text-slate-300">
          <li className={passwordLengthValid ? 'text-[#00FF41]' : 'text-slate-600'}>At least 8 characters</li>
          <li className={passwordUpperValid ? 'text-[#00FF41]' : 'text-slate-600'}>An uppercase letter</li>
          <li className={passwordSpecialValid ? 'text-[#00FF41]' : 'text-slate-600'}>A special character (e.g. !@#$%)</li>
        </ul>

        <button
          type="submit"
          disabled={!allValid}
          className={`label-tech-pulse chromatic-aberration w-full py-2 rounded font-bold transition-colors ${allValid ? 'bg-[#00FF41] text-[#020202] hover:bg-[#00FF41]/80' : 'bg-slate-700 text-white cursor-not-allowed'}`}
        >
          Create account
        </button>
      </form>
    </div>
  );
};

export default Register;
